// HWC Health Check Definitions
// Uses environment variables for API keys (set in n8n systemd service)

const SONARR_KEY = process.env.SONARR_API_KEY || '';
const RADARR_KEY = process.env.RADARR_API_KEY || '';
const LIDARR_KEY = process.env.LIDARR_API_KEY || '';
const PROWLARR_KEY = process.env.PROWLARR_API_KEY || '';
const JELLYFIN_KEY = process.env.JELLYFIN_API_KEY || '';

const checks = [
  // Media Services
  { name: 'Jellyfin', url: 'http://127.0.0.1:8096/health', type: 'http', domain: 'media', timeout: 5000 },
  { name: 'Immich', url: 'http://127.0.0.1:2283/api/server/ping', type: 'http', domain: 'media', timeout: 5000 },
  { name: 'Navidrome', url: 'http://127.0.0.1:4533/rest/ping', type: 'http', domain: 'media', timeout: 5000 },
  { name: 'Audiobookshelf', url: 'http://127.0.0.1:13378/healthcheck', type: 'http', domain: 'media', timeout: 5000 },

  // Surveillance
  { name: 'Frigate', url: 'http://127.0.0.1:5001/api/stats', type: 'http', domain: 'surveillance', timeout: 5000 },

  // Arr Stack (with API keys)
  { name: 'Sonarr', url: 'http://127.0.0.1:8989/api/v3/health', type: 'http', domain: 'arr', timeout: 5000, headers: SONARR_KEY ? { 'X-Api-Key': SONARR_KEY } : {} },
  { name: 'Radarr', url: 'http://127.0.0.1:7878/api/v3/health', type: 'http', domain: 'arr', timeout: 5000, headers: RADARR_KEY ? { 'X-Api-Key': RADARR_KEY } : {} },
  { name: 'Lidarr', url: 'http://127.0.0.1:8686/api/v1/health', type: 'http', domain: 'arr', timeout: 5000, headers: LIDARR_KEY ? { 'X-Api-Key': LIDARR_KEY } : {} },
  { name: 'Prowlarr', url: 'http://127.0.0.1:9696/api/v1/health', type: 'http', domain: 'arr', timeout: 5000, headers: PROWLARR_KEY ? { 'X-Api-Key': PROWLARR_KEY } : {} },
  { name: 'Readarr', url: 'http://127.0.0.1:8787/api/v1/health', type: 'http', domain: 'arr', timeout: 5000 },

  // Downloads
  { name: 'Sabnzbd', url: 'http://127.0.0.1:8081/api?mode=queue&output=json', type: 'http', domain: 'download', timeout: 5000 },
  { name: 'qBittorrent', url: 'http://127.0.0.1:8080/api/v2/app/version', type: 'http', domain: 'download', timeout: 5000 },

  // Infrastructure
  { name: 'Grafana', url: 'http://127.0.0.1:3000/api/health', type: 'http', domain: 'monitoring', timeout: 5000 },
  { name: 'Prometheus', url: 'http://127.0.0.1:9090/-/healthy', type: 'http', domain: 'monitoring', timeout: 5000 },
  { name: 'Alertmanager', url: 'http://127.0.0.1:9093/-/healthy', type: 'http', domain: 'monitoring', timeout: 5000 },
  { name: 'ntfy', url: 'http://127.0.0.1:2586/v1/health', type: 'http', domain: 'infrastructure', timeout: 5000 },
  { name: 'CouchDB', url: 'http://127.0.0.1:5984/_up', type: 'http', domain: 'infrastructure', timeout: 5000 },

  // AI Services
  { name: 'Ollama', url: 'http://127.0.0.1:11434/api/tags', type: 'http', domain: 'ai', timeout: 10000 },
  { name: 'Open-WebUI', url: 'http://127.0.0.1:3001/health', type: 'http', domain: 'ai', timeout: 5000 },

  // Documents & Finance
  { name: 'Paperless', url: 'http://127.0.0.1:8102/api/', type: 'http', domain: 'documents', timeout: 5000 },
  { name: 'Firefly', url: 'http://127.0.0.1:8085/', type: 'http', domain: 'finance', timeout: 5000 },

  // Containers (via podman)
  { name: 'sonarr-container', container: 'sonarr', type: 'container', domain: 'arr' },
  { name: 'radarr-container', container: 'radarr', type: 'container', domain: 'arr' },
  { name: 'gluetun-container', container: 'gluetun', type: 'container', domain: 'download' },

  // Systemd Services
  { name: 'Caddy', service: 'caddy', type: 'systemd', domain: 'infrastructure' },
  { name: 'Tailscale', service: 'tailscaled', type: 'systemd', domain: 'infrastructure' },
  { name: 'n8n', service: 'n8n', type: 'systemd', domain: 'infrastructure' }
];

return checks.map(check => ({ json: check }));

// Evaluate check results and determine health status
const items = $input.all();
const checkData = items[0]?.json || {};
const response = items[items.length - 1]?.json || {};

let healthy = false;
let errorMessage = '';

if (checkData.type === 'http') {
  const statusCode = response.statusCode || response.$response?.statusCode || 0;
  healthy = (statusCode >= 200 && statusCode < 400) || (statusCode === 0 && !response.error);
  if (!healthy) {
    errorMessage = response.error?.message || `HTTP ${statusCode}` || 'Connection failed';
  }
} else if (checkData.type === 'systemd') {
  const output = (response.stdout || '').trim();
  healthy = output === 'active';
  errorMessage = healthy ? '' : `Service ${output || 'unknown'}`;
} else if (checkData.type === 'container') {
  const output = (response.stdout || '').trim();
  healthy = output === 'running';
  errorMessage = healthy ? '' : `Container ${output || 'unknown'}`;
}

return {
  json: {
    name: checkData.name,
    type: checkData.type,
    domain: checkData.domain,
    healthy,
    errorMessage,
    timestamp: new Date().toISOString()
  }
};

// STATE TRACKING: Compare with previous state to detect changes
// Uses n8n static data to persist state between executions

const results = $input.all().map(item => item.json);
const staticData = $getWorkflowStaticData('global');

// Initialize state if not present
if (!staticData.previousState) {
  staticData.previousState = {};
}
if (!staticData.alertsSent) {
  staticData.alertsSent = {};
}

const previousState = staticData.previousState;
const alertsSent = staticData.alertsSent;
const now = Date.now();
const ALERT_COOLDOWN = 30 * 60 * 1000; // 30 minutes between repeated alerts

// Categorize services
const newlyDown = [];
const stillDown = [];
const recovered = [];
const healthy = [];

results.forEach(r => {
  const wasHealthy = previousState[r.name]?.healthy !== false;
  const isHealthy = r.healthy;

  if (isHealthy) {
    healthy.push(r);
    if (!wasHealthy) {
      recovered.push(r);
    }
    // Clear alert tracking for recovered services
    delete alertsSent[r.name];
  } else {
    if (wasHealthy) {
      newlyDown.push(r);
      alertsSent[r.name] = now;
    } else {
      // Check if we should re-alert (cooldown expired)
      const lastAlert = alertsSent[r.name] || 0;
      if (now - lastAlert > ALERT_COOLDOWN) {
        stillDown.push({ ...r, isRepeated: true });
        alertsSent[r.name] = now;
      } else {
        stillDown.push({ ...r, isRepeated: false });
      }
    }
  }

  // Update state
  previousState[r.name] = { healthy: isHealthy, timestamp: r.timestamp };
});

// Save state
staticData.previousState = previousState;
staticData.alertsSent = alertsSent;

// Determine what notifications to send
const shouldNotifyDown = newlyDown.length > 0 || stillDown.some(s => s.isRepeated);
const shouldNotifyRecovery = recovered.length > 0;

return {
  json: {
    summary: {
      total: results.length,
      healthy: healthy.length,
      unhealthy: newlyDown.length + stillDown.length
    },
    newlyDown,
    stillDown,
    recovered,
    healthy,
    shouldNotifyDown,
    shouldNotifyRecovery,
    timestamp: new Date().toISOString()
  }
};

// Build Slack notification blocks
const data = $input.first().json;
const { newlyDown, stillDown, recovered, summary } = data;

const blocks = [];
const messages = [];

// NEWLY DOWN - Critical alert
if (newlyDown.length > 0) {
  blocks.push({
    type: 'header',
    text: { type: 'plain_text', text: ':rotating_light: Services Down', emoji: true }
  });

  const downList = newlyDown.map(s => 
    `:x: *${s.name}* - ${s.errorMessage}`
  ).join('\n');

  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: downList }
  });

  messages.push({
    channel: '#hwc-alerts',
    text: `:rotating_light: ${newlyDown.length} service(s) DOWN: ${newlyDown.map(s => s.name).join(', ')}`,
    blocks: [...blocks],
    severity: 'critical'
  });
  blocks.length = 0; // Reset for next message
}

// RECOVERED - Success notification
if (recovered.length > 0) {
  blocks.push({
    type: 'header',
    text: { type: 'plain_text', text: ':white_check_mark: Services Recovered', emoji: true }
  });

  const recoveredList = recovered.map(s => 
    `:white_check_mark: *${s.name}* is back online`
  ).join('\n');

  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: recoveredList }
  });

  messages.push({
    channel: '#hwc-system',
    text: `:white_check_mark: ${recovered.length} service(s) recovered: ${recovered.map(s => s.name).join(', ')}`,
    blocks: [...blocks],
    severity: 'success'
  });
  blocks.length = 0;
}

// Add timestamp to all messages
messages.forEach(msg => {
  msg.blocks.push({
    type: 'context',
    elements: [{
      type: 'mrkdwn',
      text: `Checked at ${new Date().toLocaleString('en-US', { timeZone: 'America/Denver' })} | ${summary.healthy}/${summary.total} healthy`
    }]
  });
});

return messages.map(msg => ({ json: msg }));
